  backupAndWrite("src/renderer/room_controls.js", "export function createRoomControls({ manager, renderLayoutList, updateInspector, saveLayout, undo, redo, toast, grid }) {\n  let gridEnabled = true;\n  let collisionEnabled = true;\n\n  async function handleKey(event) {\n    const tag = String(event.target?.tagName || \"\").toLowerCase();\n    if (tag === \"input\" || tag === \"textarea\" || tag === \"select\") return;\n\n    const key = event.key.toLowerCase();\n    const fine = event.shiftKey;\n\n    if (event.ctrlKey && key === \"s\") {\n      event.preventDefault();\n      await saveLayout();\n      return;\n    }\n    if (event.ctrlKey && key === \"z\") {\n      event.preventDefault();\n      await undo();\n      return;\n    }\n    if (event.ctrlKey && (key === \"y\" || (event.shiftKey && key === \"z\"))) {\n      event.preventDefault();\n      await redo();\n      return;\n    }\n\n    if (event.key === \"Delete\" || event.key === \"Backspace\") {\n      manager.remove();\n      renderLayoutList();\n      updateInspector();\n      return;\n    }\n\n    if (event.key === \"1\") { manager.setMode(\"translate\"); toast(\"Modo mover\"); return; }\n    if (event.key === \"2\") { manager.setMode(\"rotate\"); toast(\"Modo girar\"); return; }\n    if (event.key === \"3\") { manager.setMode(\"scale\"); toast(\"Modo escalar\"); return; }\n\n    const map = { w: [0, 0, -1], s: [0, 0, 1], a: [-1, 0, 0], d: [1, 0, 0], q: [0, 1, 0], e: [0, -1, 0] };\n    if (map[key]) {\n      const [x, y, z] = map[key];\n      manager.moveSelected(x, y, z, fine);\n      updateInspector();\n      return;\n    }\n\n    if (event.key === \"ArrowLeft\") { manager.rotateSelected(15, fine); updateInspector(); }\n    if (event.key === \"ArrowRight\") { manager.rotateSelected(-15, fine); updateInspector(); }\n    if (event.key === \"+\" || event.key === \"=\") { manager.scaleSelected(0.05); updateInspector(); }\n    if (event.key === \"-\" || event.key === \"_\") { manager.scaleSelected(-0.05); updateInspector(); }\n\n    if (key === \"g\") toggleGrid();\n    if (key === \"c\") toggleCollision();\n    if (key === \"f\") updateInspector(true);\n  }\n\n  function toggleGrid() {\n    gridEnabled = !gridEnabled;\n    if (grid) grid.visible = gridEnabled;\n    toast(gridEnabled ? \"Grid ligado\" : \"Grid desligado\");\n    return gridEnabled;\n  }\n\n  function toggleCollision() {\n    collisionEnabled = !collisionEnabled;\n    manager.setCollisionEnabled(collisionEnabled);\n    toast(collisionEnabled ? \"Valida\u00e7\u00e3o de colis\u00e3o ligada\" : \"Valida\u00e7\u00e3o de colis\u00e3o desligada\");\n    return collisionEnabled;\n  }\n\n  window.addEventListener(\"keydown\", handleKey);\n\n  return {\n    destroy() { window.removeEventListener(\"keydown\", handleKey); },\n    toggleGrid,\n    toggleCollision\n  };\n}\n");
  backupAndWrite("src/renderer/room_history.js", "import { safeLayout } from \"./room_layout_store.js\";\n\nexport function createRoomHistory({ getLayout, applyLayout, limit = 50, onChange }) {\n  let stack = [];\n  let index = -1;\n  let restoring = false;\n\n  function same(a, b) {\n    return JSON.stringify(a) === JSON.stringify(b);\n  }\n\n  function notify() {\n    onChange?.({ canUndo: index > 0, canRedo: index >= 0 && index < stack.length - 1, index, length: stack.length });\n  }\n\n  function reset(layout) {\n    stack = [safeLayout(layout)];\n    index = 0;\n    notify();\n  }\n\n  function push(label = \"change\") {\n    if (restoring) return;\n    const snapshot = safeLayout(getLayout());\n    if (index >= 0 && same(stack[index], snapshot)) return;\n    stack = stack.slice(0, index + 1);\n    stack.push({ ...snapshot, label });\n    if (stack.length > limit) stack.shift();\n    index = stack.length - 1;\n    notify();\n  }\n\n  async function undo() {\n    if (index <= 0) {\n      notify();\n      return false;\n    }\n    index -= 1;\n    restoring = true;\n    await applyLayout(stack[index]);\n    restoring = false;\n    notify();\n    return true;\n  }\n\n  async function redo() {\n    if (index >= stack.length - 1) {\n      notify();\n      return false;\n    }\n    index += 1;\n    restoring = true;\n    await applyLayout(stack[index]);\n    restoring = false;\n    notify();\n    return true;\n  }\n\n  function state() {\n    return { canUndo: index > 0, canRedo: index >= 0 && index < stack.length - 1, index, length: stack.length };\n  }\n\n  return { reset, push, undo, redo, state };\n}\n");
  backupAndWrite("src/renderer/room_autosave.js", "import { safeLayout } from \"./room_layout_store.js\";\n\nconst KEY = \"noelle_room_autosave_v18_4\";\n\nexport function saveRoomAutosave(layout) {\n  try {\n    const payload = {\n      savedAt: new Date().toISOString(),\n      layout: safeLayout(layout)\n    };\n    localStorage.setItem(KEY, JSON.stringify(payload));\n    return { ok: true, payload };\n  } catch (err) {\n    return { ok: false, error: String(err?.message || err) };\n  }\n}\n\nexport function loadRoomAutosave() {\n  try {\n    const raw = localStorage.getItem(KEY);\n    if (!raw) return { ok: false, reason: \"empty\" };\n    const payload = JSON.parse(raw);\n    return { ok: true, savedAt: payload.savedAt, layout: safeLayout(payload.layout) };\n  } catch (err) {\n    return { ok: false, error: String(err?.message || err) };\n  }\n}\n\nexport function clearRoomAutosave() {\n  try {\n    localStorage.removeItem(KEY);\n    return { ok: true };\n  } catch (err) {\n    return { ok: false, error: String(err?.message || err) };\n  }\n}\n\nexport function createAutosaveScheduler({ getLayout, onStatus, intervalMs = 1200 }) {\n  let timer = null;\n  let lastHash = \"\";\n\n  function schedule() {\n    clearTimeout(timer);\n    timer = setTimeout(() => {\n      const layout = safeLayout(getLayout());\n      const hash = JSON.stringify(layout);\n      if (hash === lastHash) return;\n      lastHash = hash;\n      const result = saveRoomAutosave(layout);\n      if (result.ok) onStatus?.(`Autosave: ${new Date(result.payload.savedAt).toLocaleTimeString()}`);\n      else onStatus?.(\"Autosave falhou\");\n    }, intervalMs);\n  }\n\n  function flush() {\n    clearTimeout(timer);\n    const layout = safeLayout(getLayout());\n    lastHash = JSON.stringify(layout);\n    return saveRoomAutosave(layout);\n  }\n\n  function destroy() {\n    clearTimeout(timer);\n  }\n\n  return { schedule, flush, destroy };\n}\n");
